import{_ as a,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"42. Uniforms And Protective Clothing","description":"","frontmatter":{"title":"42. Uniforms And Protective Clothing","eba":"Health Allied & Managers Admin 2021-2025","topics":["allowances","uniforms"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/allowances/42-uniforms-and-protective-clothing.md","filePath":"ebas/has-managers-admin/common-terms/allowances/42-uniforms-and-protective-clothing.md"}'),l={name:"ebas/has-managers-admin/common-terms/allowances/42-uniforms-and-protective-clothing.md"};function t(s,e,i,c,h,d){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_42-uniforms-and-protective-clothing" tabindex="-1">42. Uniforms And Protective Clothing <a class="header-anchor" href="#_42-uniforms-and-protective-clothing" aria-label="Permalink to &quot;42. Uniforms And Protective Clothing&quot;">​</a></h1><p>This clause does not apply to Dental Assistants employed by DHSV or Ballarat Health Service</p><p><strong>42.1</strong> Where an Employee is required to wear a uniform or any special clothing, the Employer will supply such uniform at no cost to the Employee and will replace it where necessary on a fair ‘wear and tear’ basis.</p><p><strong>42.2</strong> Uniforms and special clothing provided in accordance with subclause 42.1 will remain the property of the Employer.</p><p><strong>42.3</strong> Employees will be paid a uniform allowance in accordance with <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> and <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a> for purchasing uniform and special clothing, where they are not provided by the Employer under subclause 42.1. The uniform allowance is payable for all absences on paid leave, other than absences on long service leave and sick leave beyond 21 days. Where, prior to the taking of leave, an Employee was paid a uniform allowance other than at the weekly rate, the rate payable is the average of the allowance paid during the four weeks immediately preceding the taking of leave.</p><p><strong>42.4</strong> Where Employees are responsible for laundering uniforms and special clothing, the Employer will pay the laundry allowances set out in the rates table in <a href="/eba/ebas/has-managers-admin/schedules/2c-allowances-health-allied-services.html">Schedule 2C</a> and <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a>. The Employee will be paid a laundry allowance per day or part thereof on duty, or an allowance per week, whichever is the lesser amount. The laundry allowance is not payable for absences of any kind.</p><p><strong>42.5</strong> The Employer will provide such gloves, masks, protective clothing and safety appliances as are required for an Employee to properly and safely perform their job function. Where the Employee is required to purchase such clothing and equipment, they will be reimbursed in full by the Employer.</p><p>Plain language terms: uniform allowance, laundry allowance, PPE.</p>',8)])])}const u=a(l,[["render",t]]);export{p as __pageData,u as default};
